import { filterCookies, getCookiesFromHeaders } from './cookies-utils';
import { removeParametersFromUrl, urlWithTrailingSlash } from './url-utils';

export function isRedirectedTo(location: string, response: any): boolean {
  if (response.status === 302) {
    if (response.headers && response.headers.location) {
      const redirectionTo = removeParametersFromUrl(response.headers.location);
      // Some apps (e.g. GFE) add ":443" suffixes which break comparisons
      // Some apps send redirection without a trailing slash (e.g. S2P), some do
      return (
        urlWithTrailingSlash(redirectionTo.replace(':443', '')) ===
        urlWithTrailingSlash(location.replace(':443', ''))
      );
    } else {
      throw new Error('302 status without proper redirection information');
    }
  } else {
    return false;
  }
}

export function isCookieSet(partialKey: string, response: any): boolean {
  return (
    filterCookies(getCookiesFromHeaders(response), partialKey).length === 1
  );
}
